/**
 * Replacement for the legacy OrderSvc class.
 * Uses the full domain name OrderFulfillmentService as required by the ubiquitous language.
 */
class OrderFulfillmentService {
    private final OrderRepository orderRepository;
    private final InventoryService inventoryService;

    OrderFulfillmentService(OrderRepository orderRepository, InventoryService inventoryService) {
        this.orderRepository = orderRepository;
        this.inventoryService = inventoryService;
    }

    void fulfillOrder(OrderId orderId) {
        Order order = orderRepository.findById(orderId)
            .orElseThrow(() -> new OrderNotFoundException(orderId));
        inventoryService.reserveItemsForOrder(order);
        order.markAsFulfilled();
        orderRepository.save(order);
    }
}
